import React from "react";
import styles from "./nav-list.module.css";



const NavList: React.FC= () => {
  return (
    <ul>
        <li>
          <a href="/somepage" className={styles.item_link}>
            New season
          </a>
        </li>
        <li>
          <a href="/somepage" className={styles.item_link}>
            Most searched
          </a>
        </li>
        <li className={styles.list_item}>
          <a href="/somepage" className={styles.item_link}>
            Most
          </a>
        </li>
    </ul>
  );
};

export default NavList;




